index 3f3f6c6e0d1a..8b8762b9ec8e 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4607,6 +4607,12 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+    // select (select X, Y, false), true, Y -> Y
+    // select (select X, Y, false), Y, true -> Y
+    if (match(Cond, m_Select(m_Value(X), m_Value(Y), m_Zero())) &&
+        ((match(TrueVal, m_One()) && FalseVal == Y) ||
+         (match(FalseVal, m_One()) && TrueVal == Y)))
+      return Y;
   }

   // select ?, X, X -> X

